#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char S[150001];
        scanf("%s", S);
        int N = strlen(S);
        int seconds = 0;
        while (1) {
            int changed = 0;
            char new_S[N + 1];
            strcpy(new_S, S);
            for (int i = 0; i < N; i++) {
                int max_type = S[i] - '0';
                for (int j = 0; j < N; j++) {
                    if (abs(i - j) <= max_type - (S[j] - '0')) {
                        max_type = (max_type > (S[j] - '0')) ? max_type : (S[j] - '0');
                    }
                }
                if (max_type != (S[i] - '0')) {
                    changed = 1;
                }
                new_S[i] = max_type + '0';
            }
            strcpy(S, new_S);
            if (!changed) break;
            seconds++;
        }
        printf("%d\n", seconds);
    }
    return 0;
}

