import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            String S = sc.next();
            int N = S.length();
            int seconds = 0;
            while (true) {
                int changed = 0;
                char[] new_S = S.toCharArray();
                for (int i = 0; i < N; i++) {
                    int max_type = S.charAt(i) - '0';
                    for (int j = 0; j < N; j++) {
                        if (Math.abs(i - j) <= max_type - (S.charAt(j) - '0')) {
                            max_type = (max_type > (S.charAt(j) - '0')) ? max_type : (S.charAt(j) - '0');
                        }
                    }
                    if (max_type != (S.charAt(i) - '0')) {
                        changed = 1;
                    }
                    new_S[i] = (char) (max_type + '0');
                }
                S = new String(new_S);
                if (changed == 0) break;
                seconds++;
            }
            System.out.println(seconds);
        }
    }
}

