const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];

const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const S = readline().trim();
    const N = S.length;
    let seconds = 0;
    while (true) {
        let changed = 0;
        const new_S = S.split('');
        for (let j = 0; j < N; j++) {
            let max_type = parseInt(S[j]);
            for (let k = 0; k < N; k++) {
                if (Math.abs(j - k) <= max_type - parseInt(S[k])) {
                    max_type = Math.max(max_type, parseInt(S[k]));
                }
            }
            if (max_type !== parseInt(S[j])) {
                changed = 1;
            }
            new_S[j] = max_type.toString();
        }
        S = new_S.join('');
        if (!changed) break;
        seconds++;
    }
